protected checkAndUpdateOverlay() {
  const fullScreenWindows = this.openWindows.filter((w) => w.state === NbWindowState.FULL_SCREEN);
  if (fullScreenWindows.length > 0) {
    this.blockScrollStrategy.enable();
  } else {
    this.blockScrollStrategy.disable();
  }

  if (fullScreenWindows.some((w) => w.config.hasBackdrop)) {
    this.overlayRef.backdropElement.removeAttribute('hidden');
  } else {
    this.overlayRef.backdropElement.setAttribute('hidden', '');
  }
}

protected redirectResults: { [key: string]: Function } = {
  [NbOAuth2ResponseType.CODE]: () => {
    return observableOf(this.route.snapshot.queryParams).pipe(
      map((params: any) => !!(params && (params.code || params.error))),
    );
  },
  [NbOAuth2ResponseType.TOKEN]: () => {
    return observableOf(this.route.snapshot.fragment).pipe(
      map((fragment) => this.parseHashAsQueryParams(fragment)),
      map((params: any) => !!(params && (params.access_token || params.error))),
    );
  },
};

if (!this.card4().isHydrated) {
  this.logEvent(`Timer fired: Hydrating Module#4`);
  cardSignal.update((c) => ({...c, isHydrating: true}));
  await this.wait(800);
  this.card4.update((c) => ({...c, isHydrating: false, isHydrated: true}));

  if (cardSignal().penddingEvents > 0) {
    this.logEvent(`Replaying ${cardSignal().penddingEvents} queued event(s)...`);
    await this.wait(600);
    this.processPendingEvents(cardSignal);
  }
}

return [
  provideAppInitializer(async () => {
    const appOperations = inject(ApplicationOperations);
    const keyedItem = await appOperations.getStorageItems([SETTINGS_STORE_KEY]);
    const data = (keyedItem[SETTINGS_STORE_KEY] ?? {}) as {[key: string]: unknown};
    savedSettings = applyMigrations(data, appOperations);
  }),
  {
    provide: SettingsStore,
    useFactory: () => new SettingsStore(savedSettings),
  },
  Settings,
];

createQueryParams(redirectToParams: Params, actualParams: Params): Params {
  const res: Params = {};
  Object.entries(redirectToParams).forEach(([k, v]) => {
    const copySourceValue = typeof v === 'string' && v[0] === ':';
    if (copySourceValue) {
      const sourceName = v.substring(1);
      res[k] = actualParams[sourceName];
    } else {
      res[k] = v;
    }
  });
  return res;
}

export const sortGroupedRows = <TRow>(
  groupedRows: Group<TRow>[],
  columns: TableColumnInternal[],
  dirs: SortPropDir[],
  sortOnGroupHeader: SortPropDir | undefined
): Group<TRow>[] => {
  if (sortOnGroupHeader) {
    groupedRows = sortRows(groupedRows, columns, dirs, sortOnGroupHeader);
  }
  return groupedRows.map(group => ({ ...group, value: sortRows(group.value, columns, dirs) }));
};

export function isMonthDisabled(date: Date, min?: Date, max?: Date): boolean {
  const minBound = min && isBefore(endOf(date, 'month'), min, 'day');
  const maxBound = max && isAfter(startOf(date, 'month'), max, 'day');

  return minBound || maxBound || false;
}

export function isYearDisabled(date: Date, min?: Date, max?: Date): boolean {
  const minBound = min && isBefore(endOf(date, 'year'), min, 'day');
  const maxBound = max && isAfter(startOf(date, 'year'), max, 'day');

  return minBound || maxBound || false;
}

switch (direction) {
  case 'left':
    return animationFrame === 0 ? WALK_LEFT_1 : WALK_LEFT_2;
  case 'right':
    return animationFrame === 0 ? WALK_RIGHT_1 : WALK_RIGHT_2;
  case 'up':
    return animationFrame === 0 ? WALK_UP_1 : WALK_UP_2;
  case 'down':
    return animationFrame === 0 ? WALK_DOWN_1 : WALK_DOWN_2;
  default:
    return STAND;
}

switch (metadata.framework) {
  case Framework.Angular:
    const {majorVersion, minorVersion} = this.appData();

    // Show legacy `Default` for pre-v21.2
    const isPre21_2 =
      (0 < majorVersion && majorVersion < 21) || (majorVersion === 21 && minorVersion < 2);
    const ngCdMap = isPre21_2 ? ANGULAR_PRE_V21_2_CHANGE_DETECTION : ANGULAR_CHANGE_DETECTION;

    return ngCdMap[changeDetection as AngularChangeDetectionStrategy];
  case Framework.ACX:
    return ACX_CHANGE_DETECTION[changeDetection as AcxChangeDetectionStrategy];
  default:
    return undefined;
}

return (fromState: any, toState: any): boolean => {
  let lhsMatch = lhs == ANY_STATE || lhs == fromState;
  let rhsMatch = rhs == ANY_STATE || rhs == toState;

  if (!lhsMatch && LHS_MATCH_BOOLEAN && typeof fromState === 'boolean') {
    lhsMatch = fromState ? TRUE_BOOLEAN_VALUES.has(lhs) : FALSE_BOOLEAN_VALUES.has(lhs);
  }
  if (!rhsMatch && RHS_MATCH_BOOLEAN && typeof toState === 'boolean') {
    rhsMatch = toState ? TRUE_BOOLEAN_VALUES.has(rhs) : FALSE_BOOLEAN_VALUES.has(rhs);
  }

  return lhsMatch && rhsMatch;
};

context.report({
  messageId: 'i18nAttribute',
  loc: keyOrSourceSpanLoc,
  data: { attributeName },
  fix: (fixer) => {
    const { end } = parserServices.convertNodeSourceSpanToLoc(sourceSpan);
    const endIndex = sourceCode.getIndexFromLoc(end);
    return fixer.insertTextAfterRange(
      [endIndex, endIndex],
      ` i18n-${attributeName}`,
