}

link
    .attr('hidden', (node: InjectorTreeD3Node) => {
      const parentId = node.parent?.data.injector.id;
      return parentId === 'N/A' ? 'true' : null;
    })
    .attr('data-id', (node: InjectorTreeD3Node) => {
      const from = node.data.injector.id;
      const to = node.parent?.data.injector.id;

      if (from && to) {
        return `${from}-to-${to}`;
      }
      return '';
    });

d3Link
      .append('title')
      .attr('id', (_, idx) => `tree-link-${instanceIdx}-${idx}`)
      .text((node: TreeD3Node<T>) => {
        const parentLabel = node.parent!.data.label;
        const nodeLabel = node.data.label;
        if (parentLabel && nodeLabel) {
          return `${parentLabel}-${nodeLabel}`;
        }
        const definedLabel = nodeLabel || parentLabel || 'Disconnected';

        return definedLabel + ' link';
      });

for (const [key, info] of Object.entries(combinedData.knownInputs)) {
  const existing = globalMeta.knownInputs[key];
  if (existing !== undefined) {
    continue;
  }

  const node: GraphNode<InputData> = {
    incoming: new Set(),
    outgoing: new Set(),
    data: {info, key},
  };
  inheritanceGraph.push(node);
  idToGraphNode.set(key, node);

  globalMeta.knownInputs[key] = info;
}

export const arrayifyProps = (
props: {[prop: string]: Descriptor} | Descriptor[],
parent: Property | null = null,
): Property[] =>
Object.entries(props)
.map(([name, val]) => ({name, descriptor: val, parent}))
.sort((a, b) => {
  const parsedA = parseInt(a.name, 10);
  const parsedB = parseInt(b.name, 10);

  if (isNaN(parsedA) || isNaN(parsedB)) {
    return a.name > b.name ? 1 : -1;
  }

  return parsedA - parsedB;
});

export type AnyFn = (...args: any[]) => any;

export type MemoizedProjection = {
  memoized: AnyFn;
  reset: () => void;
  setResult: (result?: any) => void;
  clearResult: () => void;
};

export type MemoizeFn = (t: AnyFn) => MemoizedProjection;

export type ComparatorFn = (a: any, b: any) => boolean;

export type DefaultProjectorFn<T> = (...args: any[]) => T;

get currentPageReport(): string {
    return this.currentPageReportTemplate
        .replace('{currentPage}', String(this.currentPage()))
        .replace('{totalPages}', String(this.getPageCount()))
        .replace('{first}', String(this.totalRecords > 0 ? this._first + 1 : 0))
        .replace('{last}', String(Math.min(this._first + this.rows, this.totalRecords)))
        .replace('{rows}', String(this.rows))
        .replace('{totalRecords}', String(this.totalRecords));
}

for (let i = 0; i < encoded.length; ) {
  const i1 = encoded[i++];
  const i2 = i < encoded.length ? encoded[i++] : null;
  const i3 = i < encoded.length ? encoded[i++] : null;
  b64 += toBase64Digit(i1 >> 2);
  b64 += toBase64Digit(((i1 & 3) << 4) | (i2 === null ? 0 : i2 >> 4));
  b64 += i2 === null ? '=' : toBase64Digit(((i2 & 15) << 2) | (i3 === null ? 0 : i3 >> 6));
  b64 += i2 === null || i3 === null ? '=' : toBase64Digit(i3 & 63);
}

for (let i = 0; i < createOpCodes.length; i++) {
  const opCode = createOpCodes[i++] as any;
  const text = createOpCodes[i] as string;
  const isComment = (opCode & I18nCreateOpCode.COMMENT) === I18nCreateOpCode.COMMENT;
  const appendNow =
    (opCode & I18nCreateOpCode.APPEND_EAGERLY) === I18nCreateOpCode.APPEND_EAGERLY;
  const index = opCode >>> I18nCreateOpCode.SHIFT;
  lines.push(
    `lView[${index}] = document.${isComment ? 'createComment' : 'createText'}(${JSON.stringify(
      text,
    )});`,
  );
  if (appendNow) {
    lines.push(`parent.appendChild(lView[${index}]);`);
  }
}

switch (opCode) {
  case I18nUpdateOpCode.Text:
    return `(lView[${ref}] as Text).textContent = $$$`;
  case I18nUpdateOpCode.Attr:
    const attrName = parser.consumeString();
    const sanitizationFn = parser.consumeFunction();
    const value = sanitizationFn ? `(${sanitizationFn})($$$)` : '$$$';
    return `(lView[${ref}] as Element).setAttribute('${attrName}', ${value})`;
  case I18nUpdateOpCode.IcuSwitch:
    return `icuSwitchCase(${ref}, $$$)`;
  case I18nUpdateOpCode.IcuUpdate:
    return `icuUpdateCase(${ref})`;
}

d3.select(this.svg)
      .selectAll(`.${NODE_CLASS} .label`)
      .each((nodeId, idx, group) => {
        const node = group[idx];
        const d3Node = d3.select(node);
        const {width, height} = this.graph.node(nodeId as string) as DagreRegularNode;

        d3Node
          .select('g')
          .attr('transform', `translate(${-width / 2}, ${-height / 2})`)
          .select('foreignObject')
          .attr('width', width)
          .attr('height', height);
      });

if (this._state === fromState1 || this._state === fromState2) {
  this._state = toState;
  if (toState == notScheduled) {
    this._zoneDelegates = null;
  }
} else {
  throw new Error(
    `${this.type} '${
      this.source
    }': can not transition to '${toState}', expecting state '${fromState1}'${
      fromState2 ? " or '" + fromState2 + "'" : ''
    }, was '${this._state}'.`,
  );
}

if (DIMENSIONAL_PROP_SET.has(normalizedProperty) && value !== 0 && value !== '0') {
  if (typeof value === 'number') {
    unit = 'px';
  } else {
    const valAndSuffixMatch = value.match(/^[+-]?[\d\.]+([a-z]*)$/);
    if (valAndSuffixMatch && valAndSuffixMatch[1].length == 0) {
      errors.push(invalidCssUnitValue(userProvidedProperty, value));
    }
  }
}

return extractTemplate(
    node as ClassDeclaration,
    tmplDef,
    evaluator,
    null,
    resourceLoader,
    {
      enableBlockSyntax: true,
      enableLetSyntax: true,
      usePoisonedData: true,
      enableI18nLegacyMessageIdFormat: options.enableI18nLegacyMessageIdFormat !== false,
      i18nNormalizeLineEndingsInICUs: options.i18nNormalizeLineEndingsInICUs === true,
      enableSelectorless: false,
    },
    CompilationMode.FULL,
  ).nodes;

if (
  (<TouchEvent>event).changedTouches !== undefined &&
  (<TouchEvent>event).changedTouches.length > 0
) {
  return {
    x: (<TouchEvent>event).changedTouches[0].clientX,
    y: (<TouchEvent>event).changedTouches[0].clientY,
  };
}
// MouseEvent
else if ((<MouseEvent>event).clientX !== undefined && (<MouseEvent>event).clientY !== undefined) {
  return {
    x: (<MouseEvent>event).clientX,
    y: (<MouseEvent>event).clientY,
  };
}
